import requests

def solve(arg1: dict) -> list[dict]:
    member_id = arg1.get('memberId')

    if not member_id:
        return {'error': 'Invalid member ID'}

    try:
        # Simulating loading state
        loading_state = {'loading': True}

        # Make the API call to fetch active challenges
        response = requests.get(f'https://api.example.com/challenges?memberId={member_id}')

        if response.status_code == 401:
            return {'error': 'Authentication required'}

        if response.status_code != 200:
            return {'error': 'Invalid member ID'}

        challenges = response.json()

        # Filter only active challenges
        active_challenges = [challenge for challenge in challenges if challenge['status'] == 'ACTIVE']

        return active_challenges

    except Exception as e:
        return {'error': str(e)}
